/* ============================================================
   admin.css — สไตล์เฉพาะหน้า Admin
   (users, roles, activity-types, academic-years, departments, classes, system-logs)
   ใช้ร่วมกับ dashboard-layout.css, table.css, buttons.css, badge.css อยู่แล้ว
   ============================================================ */

/* ---------- แถบ role บนตารางผู้ใช้ ---------- */
.role-tag {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 3px 10px;
  border-radius: var(--radius-full);
  font-size: var(--fs-tiny);
  font-weight: 500;
  background: var(--color-bg-canvas);
  color: var(--color-text-muted);
  border: 1px solid var(--color-border);
}

.role-tag.role-admin { background: var(--color-primary-light); color: var(--color-primary); border-color: var(--color-primary-soft); }
.role-tag.role-teacher { background: var(--color-status-completed-bg); color: var(--color-status-completed); border-color: transparent; }
.role-tag.role-student { background: var(--color-status-active-bg); color: var(--color-status-active); border-color: transparent; }

/* ---------- Master data CRUD card (ประเภทกิจกรรม/ปีการศึกษา/ภาควิชา/ห้องเรียน) ---------- */
.master-data-grid {
  display: grid;
  grid-template-columns: 320px 1fr;
  gap: var(--space-5);
  align-items: start;
}

.master-data-form-card {
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  padding: var(--space-5);
  position: sticky;
  top: calc(var(--topbar-height) + var(--space-4));
}

.master-data-form-card h3 {
  margin-bottom: var(--space-4);
}

.form-field { margin-bottom: var(--space-4); }

.form-field label {
  display: block;
  font-size: var(--fs-small);
  font-weight: 500;
  margin-bottom: var(--space-2);
}

.form-field input,
.form-field select,
.form-field textarea {
  width: 100%;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  padding: 10px 12px;
  font-size: var(--fs-body);
  background: var(--color-bg);
  transition: border-color var(--transition-fast), box-shadow var(--transition-fast);
}

.form-field input:focus,
.form-field select:focus,
.form-field textarea:focus {
  outline: none;
  border-color: var(--color-primary);
  box-shadow: 0 0 0 3px var(--color-primary-soft);
}

.form-field-hint {
  font-size: var(--fs-tiny);
  color: var(--color-text-faint);
  margin-top: 4px;
}

.form-actions {
  display: flex;
  gap: var(--space-2);
  margin-top: var(--space-5);
}

.form-actions .btn { flex: 1; }

/* ---------- Active academic year highlight ---------- */
.academic-year-row.is-active td:first-child {
  border-left: 3px solid var(--color-status-active);
}

/* ---------- System Logs ---------- */
.log-action-tag {
  font-size: var(--fs-tiny);
  font-weight: 500;
  padding: 2px 10px;
  border-radius: var(--radius-full);
}
.log-action-tag.login,
.log-action-tag.check_in { background: var(--color-status-active-bg); color: var(--color-status-active); }
.log-action-tag.logout { background: var(--color-bg-canvas); color: var(--color-text-muted); }
.log-action-tag.create,
.log-action-tag.grade { background: var(--color-status-completed-bg); color: var(--color-status-completed); }
.log-action-tag.update { background: var(--color-status-pending-bg); color: var(--color-status-pending); }
.log-action-tag.delete { background: var(--color-status-cancelled-bg); color: var(--color-status-cancelled); }

.log-detail-json {
  font-family: 'Kanit', monospace;
  font-size: var(--fs-tiny);
  background: var(--color-bg-canvas);
  border-radius: var(--radius-sm);
  padding: var(--space-3);
  white-space: pre-wrap;
  word-break: break-all;
  color: var(--color-text-muted);
}

@media (max-width: 1024px) {
  .master-data-grid { grid-template-columns: 1fr; }
  .master-data-form-card { position: static; }
}
